#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to check if two trees are identical
int areIdenticalTrees(Node* root1, Node* root2) {
    if (root1 == NULL && root2 == NULL) {
        return 1;
    }
    if (root1 == NULL || root2 == NULL) {
        return 0;
    }
    return (root1->val == root2->val) &&
           areIdenticalTrees(root1->left, root2->left) &&
           areIdenticalTrees(root1->right, root2->right);
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Node* root1 = createNode(1);
    Node* root2 = createNode(1);
    Node** nodes1 = (Node**)malloc(N * sizeof(Node*));
    Node** nodes2 = (Node**)malloc(M * sizeof(Node*));
    nodes1[0] = root1;
    nodes2[0] = root2;
    // Create the first tree
    for (int i = 0; i < N - 1; i++) {
        int p, c;
        char R;
        scanf("%d %d %c", &p, &c, &R);
        Node* newNode = createNode(c);
        nodes1[c - 1] = newNode;
        if (R == 'L') {
            nodes1[p - 1]->left = newNode;
        } else {
            nodes1[p - 1]->right = newNode;
        }
    }
    // Create the second tree
    for (int i = 0; i < M - 1; i++) {
        int p, c;
        char R;
        scanf("%d %d %c", &p, &c, &R);
        Node* newNode = createNode(c);
        nodes2[c - 1] = newNode;
        if (R == 'L') {
            nodes2[p - 1]->left = newNode;
        } else {
            nodes2[p - 1]->right = newNode;
        }
    }
    if (areIdenticalTrees(root1, root2)) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
    return 0;
}

