import java.util.Scanner;

// Define the class for a tree node
class Node {
    int val;
    Node left;
    Node right;
    Node(int val) {
        this.val = val;
        left = right = null;
    }
}

public class Main {
    // Function to check if two trees are identical
    public static boolean areIdenticalTrees(Node root1, Node root2) {
        if (root1 == null && root2 == null) {
            return true;
        }
        if (root1 == null || root2 == null) {
            return false;
        }
        return (root1.val == root2.val) &&
               areIdenticalTrees(root1.left, root2.left) &&
               areIdenticalTrees(root1.right, root2.right);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        Node root1 = new Node(1);
        Node root2 = new Node(1);
        Node[] nodes1 = new Node[N];
        Node[] nodes2 = new Node[M];
        nodes1[0] = root1;
        nodes2[0] = root2;
        // Create the first tree
        for (int i = 0; i < N - 1; i++) {
            int p = sc.nextInt();
            int c = sc.nextInt();
            char R = sc.next().charAt(0);
            Node newNode = new Node(c);
            nodes1[c - 1] = newNode;
            if (R == 'L') {
                nodes1[p - 1].left = newNode;
            } else {
                nodes1[p - 1].right = newNode;
            }
        }
        // Create the second tree
        for (int i = 0; i < M - 1; i++) {
            int p = sc.nextInt();
            int c = sc.nextInt();
            char R = sc.next().charAt(0);
            Node newNode = new Node(c);
            nodes2[c - 1] = newNode;
            if (R == 'L') {
                nodes2[p - 1].left = newNode;
            } else {
                nodes2[p - 1].right = newNode;
            }
        }
        if (areIdenticalTrees(root1, root2)) {
            System.out.println("YES");
        } else {
            System.out.println("NO");
        }
    }
}

